+    #[test]
+    fn region_all_variants_have_distinct_urls() {
+        let urls: Vec<&str> = [
+            DatadogRegion::Us1,
+            DatadogRegion::Us3,
+            DatadogRegion::Us5,
+            DatadogRegion::Eu1,
+            DatadogRegion::Ap1,
+        ]
+        .iter()
+        .map(|r| r.api_base_url())
+        .collect();
+        let mut unique = urls.clone();
+        unique.sort_unstable();
+        unique.dedup();
+        assert_eq!(urls.len(), unique.len());
+    }
+
+    #[test]
